@startuml
!theme plain
title BADEXAMPLE's Class Diagram

package "solid" as solid {
  package "liskov" as liskov {
    package "badexample" as badexample {
      class Rectangle {
        - height : int
        - width : int
        + area()
        + getHeight()
        + getWidth()
        + setHeight()
        + setWidth()
      }

      class Square {
        + setHeight()
        + setWidth()
      }

      class RectangleTest {
        + areaShouldBeCalculatedCorrectlyWithDerivedClassSquare()
        + areaShouldBeCalculatedCorrectlyWithRectangle()
      }

      Rectangle <|-- Square
    }
  }
}

@enduml
